function Wishlist() {
  const [items, setItems] = React.useState([
    {id:1,name:'REPLACE_WITH_ITEM_1',price:'REPLACE_WITH_PRICE_1',priority:'high',url:''},
    {id:2,name:'Noise-canceling headphones',price:'$299',priority:'medium',url:''},
    {id:3,name:'Mechanical keyboard',price:'$149',priority:'low',url:''}
  ]);
  const [input, setInput] = React.useState('');
  const [priceInput, setPriceInput] = React.useState('');

  const add = ()=>{
    if(!input.trim())return;
    setItems([...items,{id:Date.now(),name:input,price:priceInput||'$0',priority:'medium',url:''}]);
    setInput('');setPriceInput('');
  };

  const remove = (id)=>setItems(items.filter(i=>i.id!==id));
  const setPrio = (id,prio)=>setItems(items.map(i=>i.id===id?{...i,priority:prio}:i));

  const pColor = {high:'#FF3B30',medium:'#FF9500',low:'#34C759'};

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Wishlist</div>
      <div style={{display:'flex',gap:6,marginBottom:12}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&add()}
          style={{flex:1,padding:'6px 10px',borderRadius:6,border:'1px solid #ccc',fontSize:13}} placeholder="Item…"/>
        <input value={priceInput} onChange={e=>setPriceInput(e.target.value)}
          style={{width:60,padding:'6px 10px',borderRadius:6,border:'1px solid #ccc',fontSize:13}} placeholder="$"/>
        <button onClick={add}
          style={{padding:'6px 12px',borderRadius:6,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          Add
        </button>
      </div>
      <div style={{flex:1,overflow:'auto'}}>
        {items.sort((a,b)=>({high:3,medium:2,low:1}[a.priority]-{high:3,medium:2,low:1}[b.priority])).map(item=> (
          <div key={item.id} style={{display:'flex',alignItems:'center',gap:8,padding:'8px 0',borderBottom:'1px solid #eee'}}>
            <button onClick={()=>setPrio(item.id,item.priority==='high'?'medium':item.priority==='medium'?'low':'high')}
              style={{width:10,height:10,borderRadius:'50%',background:pColor[item.priority],border:'none',cursor:'pointer'}}/>
            <div style={{flex:1}}>
              <div style={{fontSize:13,fontWeight:500}}>{item.name}</div>
              <div style={{fontSize:12,color:'#888'}}>{item.price}</div>
            </div>
            <button onClick={()=>remove(item.id)}
              style={{background:'none',border:'none',color:'#FF3B30',cursor:'pointer',fontSize:14}}>×</button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<Wishlist/>);
